@namespace Lumeo

@{
    var context = new DropdownMenuContext(Open, EventCallback.Factory.Create<bool>(this, SetOpen), _wrapperId, _contentId);
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="relative inline-block" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    /// <summary>The trigger and content that make up the menu (typically a <c>DropdownMenuTrigger</c> plus a <c>DropdownMenuContent</c>).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Whether the menu panel is open. Controlled together with <see cref="OpenChanged"/>; leave unbound to let the trigger own the state internally.</summary>
    [Parameter] public bool Open { get; set; }

    /// <summary>Fires whenever the open state changes (trigger click, Escape, click-outside, item selection).</summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    /// <summary>Captures any unmatched attributes and applies them to the root wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("dropdown");
    // Stable content id shared with trigger via context for aria-controls
    internal readonly string _contentId = LumeoIds.New("dropdown-content");

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    public record DropdownMenuContext(bool IsOpen, EventCallback<bool> SetOpen, string WrapperId, string ContentId);
}

@namespace Lumeo

<button type="button" role="menuitemcheckbox" aria-checked="@_checked.ToString().ToLower()" tabindex="-1" class="@CssClass" @onclick="Toggle" @attributes="AdditionalAttributes">
    <span class="flex h-3.5 w-3.5 items-center justify-center">
        @if (_checked)
        {
            <SvgGlyph Svg="@(LumeoIcons.Check)" class="h-3.5 w-3.5" />
        }
    </span>
    @ChildContent
</button>

@code {
    [CascadingParameter] private Lumeo.Density? Density { get; set; }

    /// <summary>The item's label content, rendered after the checkmark indicator.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Whether the checkbox item is checked. Controlled together with <see cref="CheckedChanged"/>; when left unbound the item tracks its own toggles internally.</summary>
    [Parameter] public bool Checked { get; set; }

    /// <summary>Fires when the user clicks the item, with the new checked state.</summary>
    [Parameter] public EventCallback<bool> CheckedChanged { get; set; }

    /// <summary>Additional CSS classes merged onto the item's root <c>button</c>.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the item's root <c>button</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Checked state lives in a private backing field, not the [Parameter]. This
    // keeps an uncontrolled item's optimistic toggle from being reverted when a
    // parent re-render pushes the same (stale) Checked value. Seeded from Checked
    // only when the parameter actually changes — mirrors DropdownMenuSub's _open.
    private bool _checked;
    private bool _lastCheckedParam;
    private bool _lastPushed;   // the last value WE emitted via CheckedChanged

    protected override void OnParametersSet()
    {
        if (CheckedChanged.HasDelegate)
        {
            // Controlled: adopt any incoming Checked that isn't the echo of our own toggle — a parent
            // veto (re-render with the OLD value) rolls the visible state back; an echo is a no-op.
            if (Checked != _lastPushed)
            {
                _checked = Checked;
                _lastPushed = Checked;
            }
        }
        else if (Checked != _lastCheckedParam)   // Uncontrolled: adopt only on a genuine param change
        {
            _checked = Checked;
            _lastCheckedParam = Checked;
        }
    }

    // Row vertical padding tracks the ambient DensityScope; Comfortable
    // reproduces the historical `py-1.5`.
    private string PadYClass => Density switch
    {
        Lumeo.Density.Compact => "py-1",
        Lumeo.Density.Spacious => "py-2.5",
        _ => "py-1.5"
    };

    private string CssClass => Cx.Merge("relative flex w-full cursor-default select-none items-center gap-2 rounded-sm", PadYClass, "ps-8 pe-2 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground", Class);

    private async Task Toggle()
    {
        _checked = !_checked;
        _lastPushed = _checked;   // record what we're about to push so a synchronous parent veto is detectable
        await CheckedChanged.InvokeAsync(_checked);
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@implements IOverlayExitCallback

@if (_exit.Present(Context.IsOpen))
{
    @* Kept mounted through the exit window (Context.IsOpen == false but _exit.Exiting)
       so the zoom/fade-out keyframe plays — Radix-Presence parity via the shared B11
       attachOverlayExitEnd infra. data-state mirrors Radix so consumers can drive
       data-[state=closed]:… CSS; the existing animate-* class stays additive. *@
    <div id="@Context.ContentId"
         role="menu"
         aria-orientation="vertical"
         data-state="@(Context.IsOpen ? "open" : "closed")"
         class="@CssClass"
         @onkeydown="HandleKeyDown"
         tabindex="-1"
         inert="@ExitInert"
         @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses"></div>
        }
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext Context { get; set; } = default!;

    /// <summary>The menu's items (typically <c>DropdownMenuItem</c>, <c>DropdownMenuGroup</c>, <c>DropdownMenuSeparator</c>, etc.).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Alignment of the panel relative to the trigger along the cross axis. Defaults to <see cref="Lumeo.Align.Start"/>.</summary>
    [Parameter] public Lumeo.Align Align { get; set; } = Lumeo.Align.Start;

    /// <summary>Which side of the trigger the panel opens on. Defaults to <see cref="Lumeo.Side.Bottom"/>.</summary>
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Bottom;

    /// <summary>When <c>true</c>, renders a small pointer arrow on the panel edge facing the trigger.</summary>
    [Parameter] public bool ShowArrow { get; set; }

    /// <summary>Additional CSS classes merged onto the panel.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the panel.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _registered;
    private int _focusedIndex = -1;
    private readonly Lumeo.Services.MenuTypeahead _typeahead = new();

    // B11 exit latch (shared infra). zoom-out fallback window sits above the 0.15s
    // CSS keyframe so the timer never preempts a slightly-late animationend on the
    // happy path (the real unmount is the panel's own animationend via
    // attachOverlayExitEnd); it only covers the JS-dead / lost-event case.
    private readonly OverlayExitAnimator _exit = new();
    private DotNetObjectReference<DropdownMenuContent>? _selfRef;
    private const int ExitDurationMs = 250;

    // Enter keeps the existing fade-in; exit uses zoom-out (scale-down + fade) —
    // the shadcn/Radix menu dismiss (data-[state=closed]:zoom-out-95 + fade-out).
    // pointer-events-none during the exit window (data-state=closed but still
    // mounted) makes the fading surface inert: a double-click / second tap can no
    // longer re-invoke a menu item while it animates out (Codex/CodeRabbit P2).
    private string AnimationClass => _exit.Exiting ? "animate-zoom-out pointer-events-none" : "animate-fade-in";

    // `inert` (exit window only) removes the menu's native <button> items from the tab
    // order so keyboard users can't Tab into the visually-closed menu mid-exit (round-2
    // P2). Focus was restored to the trigger on close, so inert traps nothing.
    private string? ExitInert => _exit.Exiting ? "true" : null;

    private string CssClass => Cx.Merge(
        "fixed z-50 min-w-[8rem] rounded-md border border-border/60 bg-popover p-1 text-popover-foreground shadow-lg",
        AnimationClass,
        ShowArrow ? "overflow-visible" : "overflow-hidden",
        Class);

    private string ArrowClasses => Side switch
    {
        Lumeo.Side.Top => "absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-r border-border/60",
        Lumeo.Side.Bottom => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60",
        Lumeo.Side.Left => "absolute top-1/2 left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-r border-border/60",
        Lumeo.Side.Right => "absolute top-1/2 right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-l border-border/60",
        _ => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60"
    };

    private string AlignStr => Align switch
    {
        Lumeo.Align.Start => "start",
        Lumeo.Align.Center => "center",
        Lumeo.Align.End => "end",
        _ => "start"
    };

    private string SideStr => Side switch
    {
        Lumeo.Side.Top => "top",
        Lumeo.Side.Left => "left",
        Lumeo.Side.Right => "right",
        _ => "bottom"
    };

    // Latch the exit on the open->closed transition so the panel stays mounted for
    // the zoom-out. Cleanup (focus restore / click-outside / unposition) still runs
    // immediately on close in OnAfterRenderAsync — unpositionFixed leaves the inline
    // top/left, so the box stays pinned while it animates out.
    protected override void OnParametersSet()
        => _exit.OnParameters(Context.IsOpen, ExitDurationMs, () => InvokeAsync(FinishExit));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(Context.ContentId, Context.WrapperId, AlignStr, false, SideStr);
            // Exclude the wrapper (the trigger lives inside it) from the
            // click-outside check. With a null exclusion, mousedown on the open
            // trigger fired this close handler first and the trigger's own click
            // then re-opened the menu — the open trigger could never close it.
            await Interop.RegisterClickOutside(Context.ContentId, Context.WrapperId, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
            _focusedIndex = -1;

            // Save the trigger's focus so it can be restored on close (WCAG 2.4.3),
            // then move focus to the menu container so Escape/ArrowUp/ArrowDown reach
            // the @onkeydown handler. saveFocus (NOT a focus trap) leaves Tab free to
            // close the menu per the WAI-ARIA menu pattern.
            try { await Interop.SaveFocus(Context.ContentId); } catch (JSDisconnectedException) { }
            try { await Interop.FocusElement(Context.ContentId); } catch (JSDisconnectedException) { }
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }

        // Once the exit render has committed the zoom-out class, hand the unmount to
        // the panel's own animationend (attachOverlayExitEnd). The fallback timer
        // stays armed for the JS-dead case. Wires once per exit.
        await _exit.WireExitAsync(async () =>
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(Context.ContentId, _selfRef); }
            catch (JSDisconnectedException) { }
        });
    }

    // Invoked from JS once the zoom-out finishes; idempotent with the fallback timer.
    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    private void FinishExit()
    {
        if (_exit.Finish()) StateHasChanged();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
            default:
                // Typeahead (Radix type-to-focus). Printable single chars (not
                // modifier combos) accumulate a query that jumps focus to the
                // first matching item. Anything else falls through untouched so
                // Tab/Enter/Space keep their native behaviour.
                if (!e.CtrlKey && !e.AltKey && !e.MetaKey && Lumeo.Services.MenuTypeahead.IsTypeaheadKey(e.Key))
                {
                    var query = _typeahead.Push(e.Key);
                    var matched = await Interop.FocusMenuItemByTypeahead(Context.ContentId, query, _focusedIndex);
                    if (matched >= 0) _focusedIndex = matched;
                }
                break;
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(Context.ContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(Context.ContentId); } catch (JSDisconnectedException) { }
        // Return focus to the trigger that opened the menu (WCAG 2.4.3) — without
        // this, dismissing via Escape / click-outside / selection drops focus to <body>.
        try { await Interop.RestoreFocus(Context.ContentId); } catch (JSDisconnectedException) { }
        _typeahead.Reset();
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        _exit.Dispose();
        _selfRef?.Dispose();
        if (_registered) await Cleanup();
    }

}

@namespace Lumeo

<div role="group" aria-label="@AriaLabel" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    /// <summary>The grouped menu items, typically a run of <c>DropdownMenuItem</c>.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Accessible name for the group's <c>role="group"</c> container, exposed via <c>aria-label</c>.</summary>
    [Parameter] public string? AriaLabel { get; set; }

    /// <summary>Additional CSS classes merged onto the group container.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the group container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);
}

@namespace Lumeo

<button class="@CssClass" role="menuitem" tabindex="-1" data-inset="@(Inset ? "true" : null)" data-variant="@VariantAttr" @onclick="HandleClick" disabled="@Disabled" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext? Context { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    /// <summary>The item's label content.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Fires when the item is activated (click or Enter/Space). The menu closes right after this callback runs.</summary>
    [Parameter] public EventCallback OnClick { get; set; }

    /// <summary>When <c>true</c>, the item is not clickable/focusable and renders with reduced opacity.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>
    /// Indents the item by a label's width so it lines up with checkbox/radio
    /// items in the same menu (shadcn <c>inset</c>). Adds <c>ps-8</c> and emits
    /// <c>data-inset</c>.
    /// </summary>
    [Parameter] public bool Inset { get; set; }

    /// <summary>
    /// Visual variant. <see cref="MenuItemVariant.Destructive"/> renders the item
    /// in the destructive color and emits <c>data-variant="destructive"</c>.
    /// </summary>
    [Parameter] public MenuItemVariant Variant { get; set; } = MenuItemVariant.Default;

    /// <summary>Additional CSS classes merged onto the item's root <c>button</c>.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the item's root <c>button</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? VariantAttr => Variant == MenuItemVariant.Destructive ? "destructive" : null;

    // Destructive items use the same class set as the library's other destructive
    // menu rows so no new Tailwind utilities are introduced.
    private const string DestructiveClass = "text-destructive hover:bg-destructive/10 hover:text-destructive focus:bg-destructive/10 focus:text-destructive";

    // Row vertical padding tracks the ambient DensityScope; Comfortable
    // reproduces the historical `py-1.5`. The mobile touch floor stays.
    private string PadYClass => Density switch
    {
        Lumeo.Density.Compact => "py-1",
        Lumeo.Density.Spacious => "py-2.5",
        _ => "py-1.5"
    };

    private string CssClass => Cx.Merge("relative flex w-full cursor-pointer select-none items-center gap-2 rounded-sm px-2", PadYClass, "min-h-11 sm:min-h-0 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed", Cx.When(Inset, "ps-8"), Cx.When(Variant == MenuItemVariant.Destructive, DestructiveClass), Class);

    private async Task HandleClick()
    {
        await OnClick.InvokeAsync();
        if (Context is not null)
        {
            await Context.SetOpen.InvokeAsync(false);
        }
    }
}

@namespace Lumeo

<div class="@CssClass" data-inset="@(Inset ? "true" : null)" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    /// <summary>The label text or markup.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Indents the label to align with inset items (shadcn <c>inset</c>).</summary>
    [Parameter] public bool Inset { get; set; }

    /// <summary>Additional CSS classes merged onto the label element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the label element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("px-2 py-1.5 text-sm font-semibold", Cx.When(Inset, "ps-8"), Class);
}

@namespace Lumeo

@{
    var context = new DropdownMenuRadioGroupContext(_value, EventCallback.Factory.Create<string>(this, OnValueSelected));
}

<CascadingValue Value="context" IsFixed="false">
    <div role="group" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    /// <summary>The group's <c>DropdownMenuRadioItem</c> options.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>The currently selected item's value. Controlled together with <see cref="ValueChanged"/>; when left unbound the group tracks the selection internally.</summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Fires when the user selects a different radio item.</summary>
    [Parameter] public EventCallback<string> ValueChanged { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the group's <c>role="group"</c> container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Selected value lives in a private backing field, not the [Parameter]. This
    // keeps an uncontrolled group's optimistic selection from being clobbered when
    // a parent re-render pushes the same (stale) Value. Seeded from Value only when
    // the parameter actually changes — mirrors DropdownMenuSub's internal _open.
    private string? _value;
    private string? _lastValueParam;
    private string? _lastPushed;   // the last value WE emitted via ValueChanged

    protected override void OnParametersSet()
    {
        if (ValueChanged.HasDelegate)
        {
            // Controlled: adopt any incoming Value that isn't the echo of our own selection — a parent
            // veto (re-render with the OLD value) rolls the visible state back; an echo is a no-op.
            if (!Equals(Value, _lastPushed))
            {
                _value = Value;
                _lastPushed = Value;
            }
        }
        else if (!Equals(Value, _lastValueParam))   // Uncontrolled: adopt only on a genuine param change
        {
            _value = Value;
            _lastValueParam = Value;
        }
    }

    private async Task OnValueSelected(string value)
    {
        _value = value;
        _lastPushed = value;   // record what we're about to push so a synchronous parent veto is detectable
        await ValueChanged.InvokeAsync(value);
    }

    public record DropdownMenuRadioGroupContext(string? Value, EventCallback<string> OnSelect);
}

@namespace Lumeo

<button type="button" role="menuitemradio" aria-checked="@IsSelected.ToString().ToLower()" tabindex="-1" class="@CssClass" @onclick="Select" @attributes="AdditionalAttributes">
    <span class="flex h-3.5 w-3.5 items-center justify-center">
        @if (IsSelected)
        {
            <SvgGlyph Svg="@(LumeoIcons.Circle)" class="h-2 w-2 fill-current" />
        }
    </span>
    @ChildContent
</button>

@code {
    [CascadingParameter] public DropdownMenuRadioGroup.DropdownMenuRadioGroupContext Context { get; set; } = default!;
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    /// <summary>The item's label content, rendered after the selection dot.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>The value this item represents. Selecting it sets the parent <c>DropdownMenuRadioGroup</c>'s value to this.</summary>
    [Parameter, EditorRequired] public string Value { get; set; } = "";

    /// <summary>Additional CSS classes merged onto the item's root <c>button</c>.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the item's root <c>button</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsSelected => Context.Value == Value;

    // Row vertical padding tracks the ambient DensityScope; Comfortable
    // reproduces the historical `py-1.5`.
    private string PadYClass => Density switch
    {
        Lumeo.Density.Compact => "py-1",
        Lumeo.Density.Spacious => "py-2.5",
        _ => "py-1.5"
    };

    private string CssClass => Cx.Merge("relative flex w-full cursor-default select-none items-center gap-2 rounded-sm", PadYClass, "ps-8 pe-2 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground", Class);

    private async Task Select() => await Context.OnSelect.InvokeAsync(Value);
}

@namespace Lumeo

<div class="@CssClass" role="none" @attributes="AdditionalAttributes"></div>

@code {
    /// <summary>Additional CSS classes merged onto the separator line.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the separator line.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("-mx-1 my-1 h-px bg-border", Class);
}

@namespace Lumeo

@* Right-aligned keyboard-shortcut hint for a DropdownMenuItem (shadcn
   DropdownMenuShortcut). Mirrors MenubarShortcut 1:1 — pushed to the inline-end
   with ms-auto and rendered in the muted color. Decorative: put the real
   accessible name on the item itself. *@
<span class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</span>

@code {
    /// <summary>The shortcut hint text (e.g. <c>"⌘K"</c>).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the shortcut <c>span</c>.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the shortcut <c>span</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("ms-auto text-xs tracking-widest text-muted-foreground", Class);
}

@namespace Lumeo
@implements IDisposable

@{
    var subContext = new DropdownMenuSubContext(
        _open,
        EventCallback.Factory.Create<bool>(this, SetOpen),
        _wrapperId,
        _triggerId,
        _contentId,
        EventCallback.Factory.Create(this, CloseTree),
        ScheduleClose,
        CancelClose,
        EventCallback.Factory.Create(this, OpenFromKeyboard),
