    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the submenu's root wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _open;
    private readonly string _wrapperId = LumeoIds.New("dropdown-sub");
    internal readonly string _triggerId = LumeoIds.New("dropdown-sub-trigger");
    internal readonly string _contentId = LumeoIds.New("dropdown-sub-content");

    private CancellationTokenSource? _closeCts;
    private bool _disposed;

    // Set when the submenu is opened via the keyboard (ArrowRight). The content
    // consumes it on its first open render to move focus to the first item —
    // race-free, replacing a fixed Task.Delay that guessed when the content existed.
    private bool _openByKeyboard;

    // Submenu teardown on ancestor exit (Codex/CodeRabbit P2): when the root menu (or
    // an enclosing submenu) closes while this submenu is open, its own _open stayed
    // true — leaving the submenu mounted with data-state="open" under a data-state=
    // "closed" parent until the whole tree unmounted. Observe the ancestor's open flag
    // (cascaded, IsFixed=false) and reset our state so the submenu exits/unmounts in
    // sync with the tree. The cascade re-renders this component whenever the root's
    // Open flips, so OnParametersSet is the right place to catch the edge.
    protected override void OnParametersSet()
    {
        var ancestorClosed = RootContext is { IsOpen: false } || ParentSubContext is { IsOpen: false };
        if (ancestorClosed && _open)
        {
            CancelClose();
            _open = false;
        }
    }

    private async Task SetOpen(bool value)
    {
        if (_open == value) return;
        _open = value;
        await InvokeAsync(StateHasChanged);
    }

    // Open from the keyboard: flag it first (before the render SetOpen triggers) so
    // the content's OnAfterRender sees it and focuses the first item.
    private async Task OpenFromKeyboard()
    {
        _openByKeyboard = true;
        await SetOpen(true);
    }

    // Consume-once: the content calls this when it first renders open and focuses
    // the first item only if the open was keyboard-initiated (hover-open must not
    // steal focus).
    private bool ConsumeKeyboardOpen()
    {
        if (!_openByKeyboard) return false;
        _openByKeyboard = false;
        return true;
    }

    private async Task CloseTree()
    {
        await SetOpen(false);
        if (ParentSubContext is not null)
        {
            await ParentSubContext.CloseTree.InvokeAsync();
        }
        else if (RootContext is not null)
        {
            await RootContext.SetOpen.InvokeAsync(false);
        }
    }

    private void CancelClose()
    {
        try { _closeCts?.Cancel(); } catch (ObjectDisposedException) { }
        _closeCts?.Dispose();
        _closeCts = null;
    }

    private void ScheduleClose()
    {
        if (_disposed) return;
        CancelClose();
        _closeCts = new CancellationTokenSource();
        var token = _closeCts.Token;
        _ = Task.Run(async () =>
        {
            try
            {
                await Task.Delay(200, token);
                if (token.IsCancellationRequested || _disposed) return;
                await InvokeAsync(async () => await SetOpen(false));
            }
            // A teardown that races the delay (Dispose cancels the token) must never
            // surface an unobserved exception or fire SetOpen on a torn-down component.
            catch (TaskCanceledException) { }
            catch (ObjectDisposedException) { }
        });
    }

    public void Dispose()
    {
        _disposed = true;
        // Cancels + disposes _closeCts and nulls it, so a scheduled close cannot
        // fire SetOpen on this torn-down component (ObjectDisposedException).
        CancelClose();
    }

    public record DropdownMenuSubContext(
        bool IsOpen,
        EventCallback<bool> SetOpen,
        string WrapperId,
        string TriggerId,
        string ContentId,
        EventCallback CloseTree,
        Action ScheduleClose,
        Action CancelClose,
        EventCallback OpenByKeyboard,
        Func<bool> ConsumeKeyboardOpen);
}

