@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public DropdownMenuSub.DropdownMenuSubContext SubContext { get; set; } = default!;

    /// <summary>The submenu's items (typically <c>DropdownMenuItem</c>, <c>DropdownMenuGroup</c>, <c>DropdownMenuSeparator</c>, etc.).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the submenu panel.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the submenu panel.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _positioned;
    private int _focusedIndex = -1;
    private readonly Lumeo.Services.MenuTypeahead _typeahead = new();
    private readonly OverlayExitAnimator _exit = new();
    private DotNetObjectReference<DropdownMenuSubContent>? _selfRef;
    private const int ExitDurationMs = 250;

    // pointer-events-none during the exit window makes the fading submenu inert so a
    // double-click / second tap can't re-invoke an item while it animates out (P2).
    private string AnimationClass => _exit.Exiting ? "animate-zoom-out pointer-events-none" : "animate-fade-in";

    // `inert` (exit window only) drops the submenu's native <button> items from the tab
    // order so keyboard users can't Tab into the closing panel (round-2 P2).
    private string? ExitInert => _exit.Exiting ? "true" : null;

    private string CssClass => Cx.Merge("fixed z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/60 bg-popover p-1 text-popover-foreground shadow-lg", AnimationClass, Class);

    protected override void OnParametersSet()
        => _exit.OnParameters(SubContext.IsOpen, ExitDurationMs, () => InvokeAsync(FinishExit));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (SubContext.IsOpen && !_positioned)
        {
            await PositionWithFlip();
            _positioned = true;
            _focusedIndex = -1;
            // Keyboard-opened (ArrowRight): move focus to the first item now that the
            // content actually exists. Hover-open does not set the flag, so it never
            // steals focus from the pointer.
            if (SubContext.ConsumeKeyboardOpen())
            {
                _focusedIndex = 0;
                try { await Interop.FocusMenuItemByIndex(SubContext.ContentId, 0); }
                catch (JSDisconnectedException) { }
            }
        }
        else if (!SubContext.IsOpen && _positioned)
        {
            // Cleanup (unpositionFixed) runs immediately on close: it stops the
            // reposition rAF and leaves the inline top/left, so the box freezes in
            // place while the zoom-out plays instead of being re-measured mid-scale.
            await Cleanup();
        }

        await _exit.WireExitAsync(async () =>
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(SubContext.ContentId, _selfRef); }
            catch (JSDisconnectedException) { }
        });
    }

    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    private void FinishExit()
    {
        if (_exit.Finish()) StateHasChanged();
    }

    private async Task PositionWithFlip()
    {
        var side = "right";
        try
        {
            var triggerRect = await Interop.GetElementRect(SubContext.TriggerId);
            var viewport = await Interop.GetViewportSize();
            // Estimate content width; flip if not enough room on the right (use 200px as conservative width).
            if (triggerRect is not null && triggerRect.X + triggerRect.Width + 200 > viewport.Width)
            {
                side = "left";
            }
        }
        catch (JSDisconnectedException) { }

        await Interop.PositionFixed(SubContext.ContentId, SubContext.TriggerId, "start", false, side);
    }

    private async Task HandleMouseEnter()
    {
        SubContext.CancelClose();
        await Task.CompletedTask;
    }

    private void HandleMouseLeave()
    {
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await SubContext.CloseTree.InvokeAsync();
                break;
            case "ArrowLeft":
                SubContext.CancelClose();
                await SubContext.SetOpen.InvokeAsync(false);
                try { await Interop.FocusElement(SubContext.TriggerId); } catch (JSDisconnectedException) { }
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            default:
                // Scoped submenu typeahead (parity with ContextMenuSubContent / the root
                // DropdownMenuContent — Radix type-to-focus). Our round-2 keydown
                // stopPropagation stops printable keys bubbling to the root menu, so
                // without this local branch type-to-focus was dead inside dropdown
                // submenus. Modifier combos fall through so Tab/Enter/Space stay native.
                if (!e.CtrlKey && !e.AltKey && !e.MetaKey && Lumeo.Services.MenuTypeahead.IsTypeaheadKey(e.Key))
                {
                    var query = _typeahead.Push(e.Key);
                    var matched = await Interop.FocusMenuItemByTypeahead(SubContext.ContentId, query, _focusedIndex);
                    if (matched >= 0) _focusedIndex = matched;
                }
                break;
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(SubContext.ContentId); } catch (JSDisconnectedException) { }
        _typeahead.Reset();
        _positioned = false;
    }

    public async ValueTask DisposeAsync()
    {
        _exit.Dispose();
        _selfRef?.Dispose();
        if (_positioned) await Cleanup();
    }
}

